    62→	private initializeAlgoliaClient(): void {
    63→		try {
    64→			const appId = getEnv<string>({ key: ALG_APP_ID });
    65→			const apiKey = getEnv<string>({ key: ALG_API_KEY });
    66→			const indexName = getEnv<string>({ key: ALG_INDEX_NAME });
    67→
    68→			if (!appId || !apiKey || !indexName) {
    69→				throw new Error('Missing Algolia configuration');
    70→			}
    71→
    72→			const client = algoliasearch(appId, apiKey);
    73→
    74→			this.algoliaClient = client;
    75→			this.algoliaClientRecommend = client.initRecommend();
    76→			this.indexName = indexName;
    77→
    78→			this.logger.log('Algolia client initialized successfully');
    79→		} catch (error: unknown) {
