    85→	public async upsertObject<T extends { objectID: string }>({
    86→		object,
    87→	}: {
    88→		object: T;
    89→	}): Promise<void> {
    90→		try {
    91→			await this.algoliaClient.saveObject({
    92→				indexName: this.indexName,
    93→				body: {
    94→					...object,
    95→				},
    96→			});
    97→			this.logger.log('Successfully upserted object to Algolia', {
    98→				objectId: object.objectID,
    99→				indexName: this.indexName,
   100→			});
   101→		} catch (error: unknown) {
   102→			this.handleError(
   103→				`Failed to upsert objects to Algolia index ${this.indexName}`,
   104→				error,
   105→			);
   106→			throw new Error(`Failed to upsert objects to Algolia index ${this.indexName}`);
