   257→	generateAlgoliaRelatedProductKey(productId: string): string {
   258→		return `style:${productId}`;
   259→	}
   260→
   261→	public async getRelatedProductIds({
   262→		productId,
   263→	}: {
   264→		productId: number;
   265→	}): Promise<number[]> {
   266→		try {
   267→			const objectIdKey = `${productId}-${ALGOLIA_OBJECT_ID_SUFFIXES[0]}`;
   268→			const cacheKey = `ids:${this.generateAlgoliaRelatedProductKey(objectIdKey)}`;
   269→			const cachedIds = await this.cacheService.get<number[]>({
   270→				namespace: Namespaces.RELATED_ITEMS_MODEL,
   271→				key: cacheKey,
   272→			});
   273→
   274→			if (cachedIds) {
   275→				this.logger.log('Cache hit for related product IDs', { productId, objectIdKey });
   276→				await this.metricsService.incrementDailyCounter(dailyTrackingKeys.CACHE_REQUESTS);
   277→				return cachedIds;
   278→			}
   279→
   280→			this.logger.log('Cache miss for related product IDs', { productId, objectIdKey });
   281→
   282→			const results = await this.algoliaClientRecommend.getRecommendations({
   283→				requests: [
   284→					{
   285→						indexName: this.indexName,
   286→						model: 'related-products',
   287→						threshold: 0,
   288→						objectID: objectIdKey,
   289→					},
   290→				],
   291→			});
   292→
   293→			const recommendationsHits = results.results[0]?.hits ?? [];
   294→			const styleIds = recommendationsHits
   295→				.map((hit) => {
   296→					const productIdValue = (hit as unknown as AlgoliaRelatedProductHit).product_id;
   297→					return typeof productIdValue === 'string'
   298→						? Number(productIdValue)
   299→						: productIdValue;
   300→				})
   301→				.filter((id): id is number => !isNaN(id));
   302→
   303→			await this.metricsService.incrementDailyCounter(dailyTrackingKeys.ALGOLIA_REQUESTS);
   304→			this.logger.log('Fetched related product IDs from Algolia', {
   305→				productId,
   306→				objectIdKey,
   307→				count: styleIds.length,
   308→			});
   309→
   310→			await this.cacheService.set({
   311→				namespace: Namespaces.RELATED_ITEMS_MODEL,
   312→				key: cacheKey,
   313→				value: styleIds,
   314→				ttl: this.relatedProductsCacheTtl,
   315→			});
   316→
   317→			return styleIds;
   318→		} catch (error: unknown) {
   319→			this.handleError(
   320→				`Error fetching related product IDs from Algolia for productId ${productId}`,
   321→				error,
   322→			);
   323→			if ((error as Error).message !== 'ObjectID does not exist') {
   324→				rollbar.error(error as Error, { productId });
   325→			}
   326→			throw new Error(`Failed to fetch related product IDs for productId ${productId}`);
   327→		}
   328→	}
