   330→	async getProductsByMultipleBrands({
   331→		brands,
   332→		limit = 100,
   333→		categoryId,
   334→	}: {
   335→		brands: string[];
   336→		limit?: number;
   337→		categoryId?: number | undefined;
   338→	}): Promise<AlgoliaRelatedProductHit[]> {
   339→		try {
   340→			if (brands.length === 0) {
   341→				return [];
   342→			}
   343→
   344→			const brandFilters = brands.map((brand) => `brand:"${brand}"`).join(' OR ');
   345→			const suffixFilter = `index_suffix:"${ALGOLIA_OBJECT_ID_SUFFIXES[0]}"`;
   346→			const categoryFilter = categoryId ? `primary_category_id:${categoryId}` : '';
   347→			const combinedFilters = categoryFilter
   348→				? `(${brandFilters}) AND ${categoryFilter} AND ${suffixFilter}`
   349→				: `(${brandFilters}) AND ${suffixFilter}`;
   350→
   351→			const result = await this.algoliaClient.searchForHits({
   352→				requests: [
   353→					{ indexName: this.indexName, filters: combinedFilters, hitsPerPage: limit },
   354→				],
   355→			});
   356→
   357→			return (result.results[0]?.hits ?? []) as unknown as AlgoliaRelatedProductHit[];
   358→		} catch (error: unknown) {
   359→			this.handleError(`Error fetching products for brands: ${brands.join(', ')}`, error);
   360→			throw new Error(`Failed to fetch products for multiple brands`);
   361→		}
   362→	}
   363→}
