   578→	private getBroadCategoryNames({
   579→		categories,
   580→		allCategories,
   581→	}: {
   582→		styleId?: number;
   583→		categories: MMSStyleToProcess['categories'];
   584→		allCategories: MMSAllStyleCategory[];
   585→	}): string[] {
   586→		const activeCategories = categories
   587→			.map((cat) => {
   588→				const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
   589→				if (fullCategory) {
   590→					cat['parent'] = fullCategory;
   591→				}
   592→				return cat;
   593→			})
   594→			.filter((cat) => cat.active);
   595→
   596→		const allParents = activeCategories
   597→			.map((category) => category['parent'] ?? { ...category, _id: category.id })
   598→			.filter(Boolean) as MMSAllStyleCategory[];
   599→
   600→		const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
   601→			if (TAXONOMY_CAT_IDS.includes(parent._id)) {
   602→				return acc;
   603→			}
   604→
   605→			if (!acc.some((p) => p._id === parent._id)) {
   606→				acc.push(parent);
   607→			}
   608→
   609→			return acc;
   610→		}, []);
   611→
   612→		const names = uniqueParents
   613→			.map((parent) => parent['name'])
   614→			.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];
   615→
   616→		return [...new Set(names)];
   617→	}
