   622→	}: {
   623→		categories: MMSStyleToProcess['categories'];
   624→		allCategories: MMSAllStyleCategory[];
   625→	}): string[] {
   626→		const activeCategories = categories.filter((cat) => cat.active && cat.parent_id);
   627→
   628→		const childCategories: string[] = [];
   629→
   630→		for (const category of activeCategories) {
   631→			const hasChildren = allCategories.some((cat) => cat['parent_id'] === category.id);
   632→
   633→			if (!hasChildren && category.name) {
   634→				childCategories.push(category.name);
   635→			}
   636→		}
   637→
   638→		return [...new Set(childCategories)];
   639→	}
