   645→	private calculateLink({
   646→		style,
   647→		allCategories,
   648→	}: {
   649→		style: MMSStyleToProcess;
   650→		allCategories: MMSAllStyleCategory[];
   651→	}): Breadcrumb | null {
   652→		function urlFriendly(str: string): string {
   653→			return str
   654→				.toLowerCase()
   655→				.replace(/&reg;/g, '®')
   656→				.replace(/\//g, '-')
   657→				.replace(/\s+/g, '-')
   658→				.replace(/[^\+\-0-9_a-z]/g, '')
   659→				.replace(/^-+|-+$/g, '')
   660→				.replace(/-+/g, '-');
   661→		}
   662→
   663→		const primaryCategory = style.primary_category;
   664→
   665→		if (!primaryCategory) {
   666→			return null;
   667→		}
   668→
   669→		const primaryCatParent = allCategories.find(
   670→			(cat) => cat._id === primaryCategory.parent_id,
   671→		);
   672→
   673→		const primaryCatParentName = primaryCatParent?.['name'] as string;
   674→		const categoryName = primaryCategory.name;
   675→
   676→		const firstPartLink = !primaryCatParent
   677→			? '/products'
   678→			: `/products/${urlFriendly(primaryCatParentName)}`;
   679→
   680→		const path = `${firstPartLink}/${urlFriendly(categoryName)}/${urlFriendly(style.name)}/${style.id}`;
   681→
   682→		return {
   683→			name: style.name,
   684→			path: path,
   685→		};
   686→	}
