   693→	private extractCategoriesWithParents({
   694→		categoryIds,
   695→		allCategories,
   696→	}: {
   697→		categoryIds: number[];
   698→		allCategories: MMSAllStyleCategory[];
   699→	}): number[] {
   700→		const allCategoryIds = new Set<number>();
   701→
   702→		for (const categoryId of categoryIds) {
   703→			allCategoryIds.add(categoryId);
   704→
   705→			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
   706→			for (const parentId of parentIds) {
   707→				allCategoryIds.add(parentId);
   708→			}
   709→		}
   710→
   711→		return Array.from(allCategoryIds).sort((a, b) => a - b);
   712→	}
   713→
   714→	private getAllParentCategoryIds({
   715→		categoryId,
   716→		allCategories,
   717→	}: {
   718→		categoryId: number;
   719→		allCategories: MMSAllStyleCategory[];
   720→	}): number[] {
   721→		const parents: number[] = [];
   722→		const category = allCategories.find((cat) => cat._id === categoryId);
   723→
   724→		if (!category?.['parent_id']) {
   725→			return parents;
   726→		}
   727→
   728→		let currentParentId = category['parent_id'] as number;
   729→
   730→		while (currentParentId) {
   731→			parents.push(currentParentId);
   732→
   733→			const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
   734→			if (!parentCategory?.['parent_id']) {
   735→				break;
   736→			}
   737→
   738→			currentParentId = parentCategory['parent_id'] as number;
   739→		}
   740→
   741→		return parents;
   742→	}
   743→
   744→	private getRootCategoryId({
   745→		style,
   746→		allCategories,
   747→	}: {
   748→		style: MMSStyleToProcess;
   749→		allCategories: MMSAllStyleCategory[];
   750→	}): number | null {
   751→		if (!style.primary_category) {
   752→			return null;
   753→		}
   754→
   755→		const primaryCategory = allCategories.find(
   756→			(cat) => cat._id === style.primary_category_id,
   757→		);
   758→		if (!primaryCategory) {
   759→			return null;
   760→		}
   761→
   762→		let currentCategory = primaryCategory;
   763→		while (currentCategory['parent_id']) {
   764→			const parentCategory = allCategories.find(
   765→				(cat) => cat._id === currentCategory['parent_id'],
   766→			);
   767→			if (!parentCategory) break;
   768→			currentCategory = parentCategory;
   769→		}
   770→
   771→		return !currentCategory['parent_id'] ? currentCategory._id : null;
   772→	}
   773→}
