    27→@Command({
    28→	name: 'prepare-promo-seed',
    29→	description: 'Prepare promotional data seed',
    30→})
    31→export class PreparePromoSeedCommand extends CommandRunner {
    32→	private readonly logger = new Logger(PreparePromoSeedCommand.name);
    33→	private readonly mmsBaseUrl = getEnv({ key: MMS_INTERNAL_BASE_URL });
    34→	private readonly ROOT_CAT_ID = 300;
    35→
    36→	constructor(private readonly algoliaService: AlgoliaService) {
    37→		super();
    38→	}
    39→
    40→	@CronJobExecution({ jobName: 'prepare-promo-seed' })
    41→	async run(): Promise<void> {
    42→		this.logger.log('Preparing promo seed...');
    43→
    44→		try {
    45→			const categories = await this.fetchMMSCategories();
    46→			this.logger.log(`Fetched ${categories.length} categories from MMS`);
    47→
    48→			const promoSeedItems: PromoSeedItem[] = [];
    49→			let processedCount = 0;
    50→			let notFoundCount = 0;
    51→
    52→			for (const item of data) {
    53→				processedCount++;
    54→				this.logger.debug(
    55→					`Processing ${processedCount}/${data.length}: ${item.product_name}`,
    56→				);
    57→
    58→				try {
    59→					const searchResult = await this.algoliaService.searchProducts({
    60→						query: item.product_name,
    61→						hitsPerPage: 1,
    62→					});
    63→
    64→					if (searchResult.hits.length === 0) {
    65→						this.logger.warn(`Product not found in Algolia: ${item.product_name}`);
    66→						notFoundCount++;
    67→						continue;
    68→					}
    69→
    70→					const product = searchResult.hits[0];
    71→					if (!product) {
    72→						this.logger.warn(`Product not found in Algolia: ${item.product_name}`);
    73→						notFoundCount++;
    74→						continue;
    75→					}
    76→					const categoryId = product.primary_category_id;
    77→
    78→					const categoryMap = new Map(categories.map((c) => [c._id, c]));
    79→
    80→					const category = categoryId ? categoryMap.get(categoryId) : null;
    81→
    82→					if (!category) {
    83→						this.logger.warn(
    84→							`Category ${categoryId} not found for product ${item.product_name}`,
    85→						);
    86→					}
    87→
    88→					const parentCategoryIds = categoryId
    89→						? this.getParentCategoryIds(categoryId, categoryMap)
    90→						: [];
    91→
    92→					const promoItem: PromoSeedItem = {
    93→						product_id: String(product.product_id),
    94→						product_name: product.name,
    95→						category_id: categoryId,
    96→						category_name: category?.['name']?.toString() ?? item.category_name,
    97→						parent_categories_ids: parentCategoryIds,
    98→					};
    99→
   100→					promoSeedItems.push(promoItem);
   101→					this.logger.debug(
   102→						`Added: ${promoItem.product_name} (ID: ${promoItem.product_id})`,
   103→					);
   104→				} catch (error) {
   105→					this.logger.error(`Error processing ${item.product_name}: ${error}`);
   106→				}
   107→			}
   108→
   109→			this.outputPromoSeedData(promoSeedItems);
   110→
   111→			this.logger.log(
   112→				`Promo seed preparation completed. Processed: ${processedCount}, Found: ${promoSeedItems.length}, Not found: ${notFoundCount}`,
   113→			);
   114→		} catch (error) {
   115→			this.logger.error('Error during promo seed preparation:', error);
   116→			throw error;
   117→		}
   118→	}
