   120→	private async fetchMMSCategories(): Promise<MMSAllStyleCategory[]> {
   121→		try {
   122→			const response = await fetch(`${this.mmsBaseUrl}/mms/api/categories.json`);
   123→			if (!response.ok) {
   124→				throw new Error(`Failed to fetch categories: ${response.statusText}`);
   125→			}
   126→			return (await response.json()) as MMSAllStyleCategory[];
   127→		} catch (error) {
   128→			this.logger.error('Failed to fetch MMS categories:', error);
   129→			throw error;
   130→		}
   131→	}
   132→
   133→	private getParentCategoryIds(
   134→		categoryId: number,
   135→		categoryMap: Map<number, MMSAllStyleCategory>,
   136→	): number[] {
   137→		const parentIds: number[] = [];
   138→		let currentCategoryId: number | null = categoryId;
   139→
   140→		while (currentCategoryId) {
   141→			const category = categoryMap.get(currentCategoryId);
   142→			if (!category) {
   143→				break;
   144→			}
   145→
   146→			const parentId = category['parent_id'];
   147→			if (!parentId || parentId === this.ROOT_CAT_ID) {
   148→				break;
   149→			}
   150→
   151→			parentIds.push(Number(parentId));
   152→			currentCategoryId = Number(parentId);
   153→		}
   154→
   155→		return parentIds.reverse();
   156→	}
