   158→	private outputPromoSeedData(items: PromoSeedItem[]): void {
   159→		const outputPath = path.join(process.cwd(), 'src', 'seeds', 'promo-seed-data.ts');
   160→
   161→		let fileContent = '// Auto-generated by prepare-promo-seed command\n';
   162→		fileContent += '// Generated on: ' + new Date().toISOString() + '\n\n';
   163→		fileContent += 'export interface PromoSeedItem {\n';
   164→		fileContent += '\tproduct_id: string;\n';
   165→		fileContent += '\tproduct_name: string;\n';
   166→		fileContent += '\tcategory_id: number | null;\n';
   167→		fileContent += '\tcategory_name: string;\n';
   168→		fileContent += '\tparent_categories_ids: number[];\n';
   169→		fileContent += '}\n\n';
   170→		fileContent += 'export const data: PromoSeedItem[] = [\n';
   171→
   172→		items.forEach((item) => {
   173→			fileContent += '\t{\n';
   174→			fileContent += `\t\tproduct_id: '${item.product_id}',\n`;
   175→			fileContent += `\t\tproduct_name: '${item.product_name.replace(/'/g, "\\'")}',\n`;
   176→			fileContent += `\t\tcategory_id: ${item.category_id},\n`;
   177→			fileContent += `\t\tcategory_name: '${item.category_name.replace(/'/g, "\\'")}',\n`;
   178→			fileContent += `\t\tparent_categories_ids: [${item.parent_categories_ids.join(', ')}],\n`;
   179→			fileContent += `\t},\n`;
   180→		});
   181→
   182→		fileContent += '];\n';
   183→
   184→		try {
   185→			fs.writeFileSync(outputPath, fileContent, 'utf-8');
   186→			this.logger.log(`Promo seed data written to: ${outputPath}`);
   187→		} catch (error) {
   188→			this.logger.error(`Failed to write promo seed data to file: ${error}`);
   189→			throw error;
   190→		}
   191→	}
   192→}
