    35→	const rollbarOptions = requestStore.get('rollbar');
    36→	if (rollbarOptions) {
    37→		mergeFieldsAndData(data, rollbarOptions);
    38→		const { issueTitle } = rollbarOptions;
    39→		if (issueTitle) {
    40→			overrideIssueTitle(data, issueTitle);
    41→		}
    42→	}
    43→}
    44→
    45→export function overrideIssueTitle(data: Rollbar.Dictionary, issueTitle: string): void {
    46→	if (isDataWithTraceChain(data)) {
    47→		const firstException = data.body.trace_chain[0];
    48→		if (isObjectWithException(firstException)) {
    49→			firstException.exception.message = issueTitle;
    50→		}
    51→	}
    52→}
    53→
    54→export function mergeFieldsAndData(
    55→	data: Rollbar.Dictionary,
    56→	rollbarOptions: RollbarOptions,
    57→): void {
    58→	data['custom'] = data['custom'] ?? {};
    59→	const custom = data['custom'] as Record<string, unknown>;
    60→	if (rollbarOptions.fields) {
    61→		Object.assign(custom, rollbarOptions.fields);
    62→	}
    63→
    64→	const fingerprint = rollbarOptions.fingerprintContext
    65→		? { fingerprintContext: rollbarOptions.fingerprintContext }
    66→		: undefined;
    67→	if (rollbarOptions.data || fingerprint) {
    68→		if (!custom['extraArgs'] || typeof custom['extraArgs'] !== 'object') {
    69→			custom['extraArgs'] = {};
    70→		}
    71→		Object.assign(
    72→			custom['extraArgs'] as Record<string, unknown>,
    73→			rollbarOptions.data,
    74→			fingerprint,
    75→		);
    76→	}
    77→}
    78→
    79→interface dataWithTraceChain extends Rollbar.Dictionary {
    80→	body: {
    81→		trace_chain: unknown[];
    82→	};
    83→}
    84→
    85→export function isDataWithTraceChain(
    86→	data: Rollbar.Dictionary,
    87→): data is dataWithTraceChain {
    88→	return (
    89→		'body' in data &&
    90→		typeof data['body'] === 'object' &&
    91→		data['body'] !== null &&
    92→		'trace_chain' in data['body'] &&
    93→		Array.isArray(data['body'].trace_chain)
    94→	);
    95→}
    96→
    97→interface isObjectWithException {
    98→	exception: {
    99→		class?: string;
   100→		message: string;
   101→	};
   102→}
   103→
   104→export function isObjectWithException(data: unknown): data is isObjectWithException {
   105→	return (
   106→		typeof data === 'object' &&
   107→		data !== null &&
   108→		'exception' in data &&
   109→		typeof data.exception === 'object' &&
   110→		data.exception !== null &&
   111→		'message' in data.exception
   112→	);
   113→}
